class Solution:
    def canMakePalindromeQueries(self, s: str, queries: List[List[int]]) -> List[bool]:
        n = len(s)
        half = n // 2
        from collections import Counter

        # Precompute prefix sums for each character
        prefix = [Counter() for _ in range(n + 1)]
        for i in range(n):
            prefix[i + 1] = prefix[i].copy()
            prefix[i + 1][s[i]] += 1

        def get_count(l, r, ch):
            return prefix[r + 1][ch] - prefix[l][ch]

        answer = []
        for a, b, c, d in queries:
            # Count characters in the first half that are not in the rearrangeable regions
            left = Counter()
            for i in range(half):
                if not (a <= i <= b):
                    left[s[i]] += 1

            # Count characters in the second half that are not in the rearrangeable regions
            right = Counter()
            for i in range(half, n):
                if not (c <= i <= d):
                    right[s[i]] += 1

            # Check if left and right can be mirrored
            is_possible = True
            for ch in left:
                if left[ch] != right.get(ch, 0):
                    is_possible = False
                    break
            answer.append(is_possible)

        return answer
